export default function ProjectFilters({
  categories = [],
  activeCategory,
  onChange,
  label = "Filter projects",
  className = "",
  size = "md", // "sm" | "md"
}) {
  const listId = useId();
  const btnRefs = useRef([]);

  const normalized = useMemo(() => {
    const unique = Array.from(
      new Map(
        (categories || [])
          .filter(Boolean)
          .map((c) => [String(c.value ?? c.id ?? c), { ...c }])
      ).values()
    );

    return unique
      .map((c) => {
        const value = String(c.value ?? c.id ?? c);
        return {
          value,
          label: String(c.label ?? c.name ?? value),
          count: Number.isFinite(c.count) ? c.count : undefined,
        };
      })
      .sort((a, b) => (a.value === "all" ? -1 : b.value === "all" ? 1 : 0));
  }, [categories]);

