  useEffect(() => {
    btnRefs.current = btnRefs.current.slice(0, normalized.length);
  }, [normalized.length]);

  const selectByIndex = (idx) => {
    const item = normalized[idx];
    if (!item) return;
    onChange?.(item.value);
