    if (!["ArrowLeft", "ArrowRight", "Home", "End", "Enter", " "].includes(e.key)) return;

    const max = normalized.length - 1;
    const dir = e.key === "ArrowRight" ? 1 : e.key === "ArrowLeft" ? -1 : 0;

    if (dir) {
      e.preventDefault();
      const next = (activeIndex + dir + normalized.length) % normalized.length;
      selectByIndex(next);
      focusByIndex(next);
      return;
    }

    if (e.key === "Home") {
      e.preventDefault();
      selectByIndex(0);
      focusByIndex(0);
      return;
    }

    if (e.key === "End") {
      e.preventDefault();
      selectByIndex(max);
      focusByIndex(max);
      return;
    }

    if (e.key === "Enter" || e.key === " ") {
      e.preventDefault();
      selectByIndex(activeIndex);
    }
