                position: "relative",
                display: "inline-flex",
                alignItems: "center",
                gap: 8,
                padding: pad,
                borderRadius: 999,
                border: "1px solid",
                borderColor: selected ? "rgba(34,211,238,.45)" : "rgba(148,163,184,.22)",
                background: selected
