import React, { useMemo, useRef } from "react";
import {
  QueryClient,
  QueryClientProvider,
  defaultShouldDehydrateQuery,
} from "@tanstack/react-query";
import { ReactQueryDevtools } from "@tanstack/react-query-devtools";

function isProd() {
  return typeof process !== "undefined" && process.env?.NODE_ENV === "production";
}

function isSerializable(value) {
  const t = typeof value;
  if (value == null || t === "string" || t === "number" || t === "boolean") return true;
  if (t === "bigint" || t === "symbol" || t === "function") return false;
  if (Array.isArray(value)) return value.every(isSerializable);
  if (t === "object") {
    if (value instanceof Date) return true;
    if (value instanceof Map || value instanceof Set) return false;
    const proto = Object.getPrototypeOf(value);
    if (proto !== Object.prototype && proto !== null) return false;
    return Object.values(value).every(isSerializable);
  }
  return false;
}

export default function QueryProvider(props) {
  const { children } = props;

  const clientRef = useRef(null);
  if (!clientRef.current) {
    clientRef.current = new QueryClient({
      defaultOptions: {
        queries: {
          retry: (failureCount, error) => {
            const status = error?.status ?? error?.response?.status;
            if (status === 401 || status === 403) return false;
            if (status >= 400 && status < 500) return failureCount < 1;
            return failureCount < 2;
          },
          staleTime: 30_000,
          gcTime: 10 * 60_000,
          refetchOnWindowFocus: true,
          refetchOnReconnect: true,
          networkMode: "online",
        },
        mutations: {
          retry: (failureCount, error) => {
            const status = error?.status ?? error?.response?.status;
            if (status >= 400 && status < 500) return false;
            return failureCount < 1;
          },
          networkMode: "online",
        },
        dehydrate: {
          shouldDehydrateQuery: (query) => {
            if (!defaultShouldDehydrateQuery(query)) return false;
            const data = query.state?.data;
            return isSerializable(data);
          },
        },
      },
    });
  }

  const devtools = useMemo(() => !isProd(), []);

  return (
    <QueryClientProvider client={clientRef.current}>
      {children}
      {devtools ? (
        <ReactQueryDevtools initialIsOpen={false} buttonPosition="bottom-left" />
      ) : null}
    </QueryClientProvider>
  );
}
