                    onBlur={onBlur("name")}
                    autoComplete="name"
                    className={`${fieldBase} ${touched.name && errors.name ? "border-rose-300/60 focus:border-rose-300/70 focus:ring-rose-300/20" : ""}`}
                    placeholder="Your name"
