import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";

export default function ApiClient(props) {
  const {
    baseURL = import.meta?.env?.VITE_API_BASE_URL || "/api",
    tokenKey = "apg_auth_token",
    useCookies = true,
    onAuthError,
    onNetworkError,
    children,
  } = props || {};

  const [lastError, setLastError] = useState(null);

  const api = useMemo(() => {
    const instance = axios.create({
      baseURL,
      withCredentials: !!useCookies,
      headers: {
        Accept: "application/json",
      },
    });

    instance.interceptors.request.use(
      (config) => {
        const token = typeof window !== "undefined" ? localStorage.getItem(tokenKey) : null;
        const headers = config.headers || {};

        if (token && !headers.Authorization) headers.Authorization = `Bearer ${token}`;
        if (!headers["X-Client-App"]) headers["X-Client-App"] = "ai-portfolio-generator";
        if (!headers["X-Client-Theme"]) headers["X-Client-Theme"] = "futuristic";

        return { ...config, headers };
      },
      (error) => Promise.reject(error)
    );

    instance.interceptors.response.use(
      (response) => response,
      (error) => {
        const status = error?.response?.status;
        const isAuthError = status === 401 || status === 403;
        const isNetworkError = !error?.response;

        const normalized = {
          at: Date.now(),
          status: status ?? null,
          code: error?.code ?? null,
          message:
            error?.response?.data?.message ||
            error?.message ||
            (isNetworkError ? "Network error" : "Request failed"),
          url: error?.config?.url || null,
          method: error?.config?.method || null,
        };

        setLastError(normalized);

        if (isAuthError) {
          if (typeof onAuthError === "function") onAuthError(normalized);
        } else if (isNetworkError) {
          if (typeof onNetworkError === "function") onNetworkError(normalized);
        }

        return Promise.reject(error);
      }
    );

    return instance;
  }, [baseURL, tokenKey, useCookies, onAuthError, onNetworkError]);

  useEffect(() => {
    const handler = (e) => {
      if (e?.key === tokenKey) {
        setLastError((prev) =>
          prev
            ? {
                ...prev,
                message: prev.message,
                tokenUpdatedAt: Date.now(),
              }
            : prev
        );
      }
    };
    window?.addEventListener?.("storage", handler);
    return () => window?.removeEventListener?.("storage", handler);
  }, [tokenKey]);

  return (
    <section aria-label="API Client Context" style={{ display: "contents" }}>
      {typeof children === "function" ? children(api, { lastError }) : children || null}
    </section>
  );
}
