    const em = values.email.trim();
    const msg = values.message.trim();
    if (!n) e.name = "Name is required.";
    if (!em) e.email = "Email is required.";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/i.test(em)) e.email = "Enter a valid email address.";
    if (!msg) e.message = "Message is required.";
    else if (msg.length < 20) e.message = "Add a bit more detail (20+ characters).";
