import React, { createContext, useCallback, useEffect, useMemo, useRef, useState } from "react";

export const AuthCtx = createContext(null);

export default function AuthContext(props) {
  const { children, storageKey = "apg_auth", apiBaseUrl = "" } = props;

  const [status, setStatus] = useState("idle"); // idle | loading | authed | anon | error
  const [token, setToken] = useState(null);
  const [user, setUser] = useState(null);
  const [lastSyncAt, setLastSyncAt] = useState(null);
  const [error, setError] = useState(null);
  const abortRef = useRef(null);

  const safeJsonParse = (v) => {
    try {
      return JSON.parse(v);
    } catch {
      return null;
    }
  };

  const persist = useCallback(
    (nextToken, nextUser) => {
      const payload = { token: nextToken || null, user: nextUser || null };
      localStorage.setItem(storageKey, JSON.stringify(payload));
    },
    [storageKey]
  );

  const clearPersisted = useCallback(() => {
    localStorage.removeItem(storageKey);
  }, [storageKey]);

  const request = useCallback(
    async (path, { method = "GET", body, auth = true } = {}) => {
      if (abortRef.current) abortRef.current.abort();
      const controller = new AbortController();
      abortRef.current = controller;

      const headers = { "Content-Type": "application/json" };
      if (auth && token) headers.Authorization = `Bearer ${token}`;

      const res = await fetch(`${apiBaseUrl}${path}`, {
        method,
        headers,
        body: body ? JSON.stringify(body) : undefined,
        signal: controller.signal,
      });

