      if (!res.ok) {
        const msg = data?.error || data?.message || `Request failed (${res.status})`;
        const e = new Error(msg);
        e.status = res.status;
        e.data = data;
        throw e;
      }
      return data;
    },
    [apiBaseUrl, token]
  );

  const me = useCallback(async () => {
    if (!token) {
      setUser(null);
      setStatus("anon");
      return null;
    }
    setStatus("loading");
    setError(null);
    try {
      const data = await request("/api/auth/me", { method: "GET", auth: true });
      const nextUser = data?.user ?? data ?? null;
      setUser(nextUser);
      setLastSyncAt(Date.now());
      setStatus(nextUser ? "authed" : "anon");
      persist(token, nextUser);
      return nextUser;
    } catch (e) {
      setError(e.message);
      setStatus("error");
      return null;
    }
  }, [persist, request, token]);

  const login = useCallback(
    async ({ email, password } = {}) => {
      setStatus("loading");
      setError(null);
      try {
