        setStatus(nextToken ? "authed" : "anon");
        persist(nextToken, nextUser);
        return { token: nextToken, user: nextUser };
      } catch (e) {
        setError(e.message);
        setStatus("error");
        return null;
      }
    },
    [persist, request]
  );

  const logout = useCallback(() => {
    if (abortRef.current) abortRef.current.abort();
    setToken(null);
    setUser(null);
    setLastSyncAt(null);
    setError(null);
    setStatus("anon");
    clearPersisted();
  }, [clearPersisted]);

  const setAuth = useCallback(
    ({ token: nextToken, user: nextUser } = {}) => {
      setToken(nextToken || null);
      setUser(nextUser || null);
      setLastSyncAt(Date.now());
      setError(null);
      setStatus(nextToken ? "authed" : "anon");
      persist(nextToken || null, nextUser || null);
    },
    [persist]
  );

